"""RAG pipeline from scratch: chunk → embed → store → retrieve → generate."""
import os
import re
import hashlib
from dataclasses import dataclass, field
from openai import OpenAI
import chromadb

client = OpenAI(api_key=os.environ["OPENAI_API_KEY"])


# ── 1. Chunking ──────────────────────────────────────────────────
@dataclass
class Chunk:
    text: str
    doc_id: str
    chunk_index: int
    source: str
    chunk_id: str = field(init=False)

    def __post_init__(self):
        self.chunk_id = hashlib.md5(f"{self.doc_id}_{self.chunk_index}".encode()).hexdigest()[:12]


def chunk_sentences(text: str, max_tokens: int = 400, overlap_sentences: int = 1) -> list[str]:
    """Split on sentence boundaries, group until max_tokens estimate."""
    sentences = re.split(r'(?<=[.!?])\s+', text.strip())
    chunks, current, current_tokens = [], [], 0
    for sent in sentences:
        sent_tokens = len(sent) // 4  # rough estimate
        if current_tokens + sent_tokens > max_tokens and current:
            chunks.append(" ".join(current))
            # Overlap: keep last N sentences for context continuity
            current = current[-overlap_sentences:]
            current_tokens = sum(len(s) // 4 for s in current)
        current.append(sent)
        current_tokens += sent_tokens
    if current:
        chunks.append(" ".join(current))
    return chunks


def chunk_document(text: str, doc_id: str, source: str) -> list[Chunk]:
    raw_chunks = chunk_sentences(text)
    return [Chunk(text=c, doc_id=doc_id, chunk_index=i, source=source) for i, c in enumerate(raw_chunks)]


# ── 2. Embedding ─────────────────────────────────────────────────
def embed_texts(texts: list[str], model: str = "text-embedding-3-small") -> list[list[float]]:
    """Batch embed — one API call for all texts."""
    if not texts:
        return []
    response = client.embeddings.create(model=model, input=texts)
    return [item.embedding for item in response.data]


# ── 3. Vector Store wrapper ──────────────────────────────────────
class RAGVectorStore:
    def __init__(self, collection_name: str = "rag_docs"):
        chroma = chromadb.PersistentClient("./rag_chroma")
        self.col = chroma.get_or_create_collection(collection_name, metadata={"hnsw:space": "cosine"})

    def add_chunks(self, chunks: list[Chunk], embeddings: list[list[float]]) -> None:
        self.col.add(
            ids=[c.chunk_id for c in chunks],
            embeddings=embeddings,
            documents=[c.text for c in chunks],
            metadatas=[{"doc_id": c.doc_id, "source": c.source, "chunk_index": c.chunk_index} for c in chunks],
        )

    def retrieve(self, query_embedding: list[float], top_k: int = 5, filters: dict | None = None) -> list[dict]:
        kwargs = {"query_embeddings": [query_embedding], "n_results": top_k, "include": ["documents", "metadatas", "distances"]}
        if filters:
            kwargs["where"] = filters
        res = self.col.query(**kwargs)
        return [
            {"text": doc, "source": meta["source"], "score": 1 - dist, "doc_id": meta["doc_id"]}
            for doc, meta, dist in zip(res["documents"][0], res["metadatas"][0], res["distances"][0])
        ]

    def count(self) -> int:
        return self.col.count()


# ── 4. Context assembly ──────────────────────────────────────────
def assemble_context(retrieved: list[dict]) -> str:
    parts = [f"[Source {i+1} — {r['source']}]\n{r['text']}" for i, r in enumerate(retrieved)]
    return "\n\n".join(parts)


# ── 5. Grounded generation ───────────────────────────────────────
RAG_SYSTEM = """You are a precise question-answering assistant.
Answer questions using ONLY the provided context sources.
If the context does not contain enough information, say: 'I don't have that information in my knowledge base.'
Cite sources using [Source N] inline for every fact you state."""

def generate_answer(query: str, context: str) -> str:
    response = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=[
            {"role": "system", "content": RAG_SYSTEM},
            {"role": "user",   "content": f"Context:\n{context}\n\nQuestion: {query}"}
        ],
        temperature=0.0,
        max_tokens=800,
    )
    return response.choices[0].message.content


# ── 6. Full RAG pipeline ─────────────────────────────────────────
class RAGPipeline:
    def __init__(self):
        self.store = RAGVectorStore()

    def index(self, documents: list[dict]) -> None:
        """Each doc: {text, doc_id, source}."""
        all_chunks: list[Chunk] = []
        for doc in documents:
            all_chunks.extend(chunk_document(doc["text"], doc["doc_id"], doc["source"]))

        print(f"Chunked into {len(all_chunks)} chunks. Embedding...")
        embeddings = embed_texts([c.text for c in all_chunks])
        self.store.add_chunks(all_chunks, embeddings)
        print(f"Indexed {self.store.count()} chunks total.")

    def query(self, question: str, top_k: int = 5) -> dict:
        query_emb = embed_texts([question])[0]
        retrieved  = self.store.retrieve(query_emb, top_k=top_k)
        context    = assemble_context(retrieved)
        answer     = generate_answer(question, context)
        return {"answer": answer, "sources": retrieved, "context_used": context}


if __name__ == "__main__":
    rag = RAGPipeline()

    rag.index([
        {"doc_id": "rag_paper", "source": "Lewis et al. 2020",
         "text": "Retrieval-Augmented Generation (RAG) is a method that combines retrieval of relevant documents with generative language models. RAG reduces hallucinations by grounding responses in retrieved evidence. The model retrieves top-K documents from a corpus using dense retrieval, then uses them as context for generation."},
        {"doc_id": "attention", "source": "Vaswani et al. 2017",
         "text": "The transformer architecture uses self-attention to process sequences in parallel. The attention mechanism computes query, key, and value matrices. Multi-head attention allows the model to attend to information from different representation subspaces."},
        {"doc_id": "gpt3", "source": "Brown et al. 2020",
         "text": "GPT-3 is a language model with 175 billion parameters trained on 300 billion tokens. It demonstrates few-shot learning capabilities without gradient updates. GPT-3 achieves strong results on NLP benchmarks using only a few examples in the prompt."},
    ])

    result = rag.query("How does RAG reduce hallucinations?")
    print("\n=== Answer ===")
    print(result["answer"])
    print("\n=== Retrieved Sources ===")
    for s in result["sources"]:
        print(f"  [{s['score']:.3f}] {s['source']}: {s['text'][:60]}...")

