def precision_at_k(retrieved_ids: list[str], relevant_ids: set[str], k: int) -> float:
    top_k = retrieved_ids[:k]
    hits = sum(1 for doc_id in top_k if doc_id in relevant_ids)
    return hits / k if k > 0 else 0.0

def evaluate_retrieval(test_cases: list[dict], rag_store, embed_fn, k: int = 5) -> dict:
    precisions = []
    for case in test_cases:
        q_emb = embed_fn([case['query']])[0]
        retrieved = rag_store.retrieve(q_emb, top_k=k)
        retrieved_ids = [r['doc_id'] for r in retrieved]
        p = precision_at_k(retrieved_ids, set(case['relevant_doc_ids']), k)
        precisions.append(p)
    return {'mean_precision_at_k': sum(precisions) / len(precisions), 'k': k}
